module top_module(d,clk,resetn,en,q);parameter WIDTH=32;

input clk;
input resetn;
input en;
input [WIDTH-1:0] d;
output [WIDTH-1:0] q;
reg [WIDTH-1:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge resetn or posedge dbg_halt)		
begin
	if (resetn==0)
		q<=0;
	else if (en==1)
		q<=d;
end

endmodule
